def main():
    os.makedirs("data", exist_ok=True)
    rows = []
    for label, posts in POSTS.items():
        for text in posts:
            rows.append({"text": text.strip(), "label": label})

    with open(OUTPUT_PATH, "w", newline="", encoding="utf-8") as f:
        writer = csv.DictWriter(f, fieldnames=["text", "label"])
        writer.writeheader()
        writer.writerows(rows)

    counts = {label: sum(1 for r in rows if r["label"] == label) for label in POSTS}
    print(f"✅ Saved {len(rows)} examples → {OUTPUT_PATH}")
    print("Label distribution:")
    for label, count in counts.items():
        print(f"  {label}: {count}")
    print("\nNext step: upload data/nba_labeled.csv to Colab Section 1.")

OUTPUT_PATH = "data/nba_labeled.csv"

if __name__ == "__main__":
    main()
